import axios from "axios";
import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import Roadmap from "../components/Roadmap";
import { useAuth } from "../context/AuthContext";
import { useProgress } from "../context/ProgressContext";

const LEVELS = [
  {
    id: 0,
    name: "Beginner",
    emoji: "🌱",
    color: "from-green-50 to-emerald-50",
    border: "border-green-200",
    badge: "bg-green-100 text-green-700",
  },
  {
    id: 1,
    name: "Elementary",
    emoji: "📖",
    color: "from-blue-50 to-sky-50",
    border: "border-blue-200",
    badge: "bg-blue-100 text-blue-700",
  },
  {
    id: 2,
    name: "Intermediate",
    emoji: "🗣️",
    color: "from-purple-50 to-violet-50",
    border: "border-purple-200",
    badge: "bg-purple-100 text-purple-700",
  },
  {
    id: 3,
    name: "Upper-Inter.",
    emoji: "📡",
    color: "from-orange-50 to-amber-50",
    border: "border-orange-200",
    badge: "bg-orange-100 text-orange-700",
  },
  {
    id: 4,
    name: "Advanced",
    emoji: "🏆",
    color: "from-pink-50 to-rose-50",
    border: "border-pink-200",
    badge: "bg-pink-100 text-pink-700",
  },
];

const DAYS_PER_LEVEL = 2;

const HomePage = () => {
  const { user } = useAuth();
  const { allProgress, fetchAllProgress } = useProgress();
  const navigate = useNavigate();
  const [levelData, setLevelData] = useState([]);
  const [loadingLevels, setLoadingLevels] = useState(true);

  useEffect(() => {
    fetchAllProgress();
    axios
      .get("/api/lessons")
      .then((r) => {
        setLevelData(r.data);
        setLoadingLevels(false);
      })
      .catch(() => setLoadingLevels(false));
  }, []);

  function getLessonProgress(levelId, day) {
    return allProgress.find((p) => p.level === levelId && p.day === day);
  }

  function isLevelUnlocked(levelId) {
    if (levelId === 0) return true;
    const prev = LEVELS[levelId - 1];
    const prevDays = Array.from({ length: DAYS_PER_LEVEL }, (_, i) => i + 1);
    return prevDays.every((d) => getLessonProgress(prev.id, d)?.isCompleted);
  }

  const totalCompleted = allProgress.filter((p) => p.isCompleted).length;
  const totalLessons = LEVELS.length * DAYS_PER_LEVEL;
  const overallPct = Math.round((totalCompleted / totalLessons) * 100);

  return (
    <div className="space-y-4 w-full max-w-4xl mx-auto px-2 sm:px-4 md:px-6 bg-[#221f35] border border-gray-700  rounded-2xl p-6 sm:p-8 transition-colors">
      {/* Welcome */}
      <div
        className="bg-gradient-to-br from-[#28323f] to-blue-800 rounded-2xl p-6 mb-5 text-white shadow-xl"
        style={{
          background: "rgba(30,41,59,.8)",
          borderRadius: 16,
          padding: 18,
          border: `1px solid #303030`,
          textAlign: "center",
        }}
      >
        <div className="flex items-center justify-between">
          <div>
            <h1 className="font-playfair text-2xl mb-1">
              Welcome back, {user?.name?.split(" ")[0]}! 👋
            </h1>
            <p className="text-blue-200 text-sm">
              Keep going — fluency is closer than you think.
            </p>
          </div>
          <div className="text-right">
            <div className="text-3xl font-extrabold">{user?.streak || 0}</div>
            <div className="text-blue-200 text-xs font-bold">🔥 day streak</div>
          </div>
        </div>
        <div className="mt-5">
          <div className="flex justify-between text-xs font-bold text-blue-200 mb-1.5">
            <span>Overall Progress</span>
            <span>
              {overallPct}% · {totalCompleted}/{totalLessons} lessons
            </span>
          </div>
          <div className="h-2.5 bg-blue-950/40 rounded-full overflow-hidden">
            <div
              className="h-full bg-gradient-to-r from-pink-400 to-yellow-300 rounded-full transition-all duration-700"
              style={{ width: `${overallPct}%` }}
            />
          </div>
        </div>
        <div className="flex gap-4 mt-4 text-center">
          <div className="flex-1 bg-white/10 rounded-xl py-2.5">
            <div className="text-xl font-extrabold">{user?.totalXP || 0}</div>
            <div className="text-blue-200 text-xs font-bold">Total XP</div>
          </div>
          <div className="flex-1 bg-white/10 rounded-xl py-2.5">
            <div className="text-xl font-extrabold">{totalCompleted}</div>
            <div className="text-blue-200 text-xs font-bold">Lessons Done</div>
          </div>
          <div className="flex-1 bg-white/10 rounded-xl py-2.5">
            <div className="text-xl font-extrabold">
              {totalLessons - totalCompleted}
            </div>
            <div className="text-blue-200 text-xs font-bold">Remaining</div>
          </div>
        </div>
      </div>

      {/* Roadmap */}
      <Roadmap
        currentLevel={user?.currentLevel || 0}
        allProgress={allProgress}
      />

      {/* Levels */}
      <h2 className="text-sm font-extrabold mb-3 flex items-center gap-2">
        📚 All Lessons
      </h2>

      {LEVELS.map((level) => {
        const unlocked = isLevelUnlocked(level.id);
        return (
          <div key={level.id} className="mb-5">
            <div className={`flex items-center gap-2 mb-2`}>
              <span className="text-xl">{level.emoji}</span>
              <h3 className="font-extrabold text-slate-300 text-sm">
                {level.name}
              </h3>
              {!unlocked && (
                <span className="text-xs text-slate-400 font-bold">
                  🔒 Complete previous level to unlock
                </span>
              )}
            </div>
            <div className="flex flex-col gap-4 w-full">
              {Array.from({ length: DAYS_PER_LEVEL }, (_, i) => {
                const dayNum = i + 1;
                const prog = getLessonProgress(level.id, dayNum);
                const isCompleted = prog?.isCompleted;
                const inProgress = prog && !isCompleted;
                const sections = prog?.completedSections || {};
                const doneSections =
                  Object.values(sections).filter(Boolean).length;
                const isLocked = !unlocked;
                const levelInfo = levelData.find((l) => l.levelId === level.id);
                const topic = levelInfo ? `Day ${dayNum}` : `Day ${dayNum}`;

                return (
                  <button
                    key={dayNum}
                    disabled={isLocked}
                    onClick={() =>
                      !isLocked && navigate(`/lesson/${level.id}/${dayNum}`)
                    }
                    className={`text-left p-4 rounded-2xl border-2 transition-all duration-200 group w-full
                      ${isLocked ? "opacity-40 cursor-not-allowed border-slate-200" : ""}
                      ${isCompleted ? ` ${level.color} ${level.border} hover:shadow-md hover:-translate-y-0.5` : ""}
                      ${inProgress ? " border-blue-300 shadow-sm hover:shadow-md hover:-translate-y-0.5" : ""}
                      ${!prog && !isLocked ? " border-slate-200 hover:border-blue-300 hover:shadow-md hover:-translate-y-0.5" : ""}`}
                  >
                    <div className="flex items-start justify-start gap-2 w-full">
                      <div className="text-2xl ">
                        {isCompleted
                          ? "🏆"
                          : inProgress
                            ? "▶️"
                            : isLocked
                              ? "🔒"
                              : "📖"}
                      </div>

                      <div>
                        <p className="font-extrabold text-gray-100 text-sm">
                          Day {dayNum}
                        </p>
                        {inProgress && (
                          <div className="mt-2">
                            <div className="h-1.5 bg-slate-800 rounded-full w-24 overflow-hidden">
                              <div
                                className="h-full bg-blue-500 rounded-full transition-all duration-500"
                                style={{
                                  width: `${(doneSections / 8) * 100}%`,
                                }}
                              />
                            </div>
                            <p className="text-xs text-slate-600 font-bold mt-0.5">
                              {doneSections}/8 sections
                            </p>
                          </div>
                        )}
                      </div>

                      <div className="flex items-center gap-2 mb-1">
                        <span
                          className={`text-xs font-extrabold px-2 py-0.5 rounded-full ${level.badge}`}
                        >
                          {level.name}
                        </span>
                        {isCompleted && (
                          <span className="text-xs font-bold text-gray-200 px-2 py-0.5 rounded-full">
                            ✓ Done
                          </span>
                        )}
                        {inProgress && (
                          <span className="text-xs font-bold text-gray-100 px-2 py-0.5 rounded-full">
                            In Progress
                          </span>
                        )}
                      </div>

                    </div>
                    {!isLocked && (
                      <p className="text-xs text-blue-900 font-bold mt-2 opacity-0 group-hover:opacity-100 transition-opacity">
                        {isCompleted
                          ? "Review lesson →"
                          : inProgress
                            ? "Continue →"
                            : "Start lesson →"}
                      </p>
                    )}
                  </button>
                );
              })}
            </div>
          </div>
        );
      })}
    </div>
  );
};

export default HomePage;
